#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, A;
        scanf("%d %d", &N, &A);
        char s[N + 1];
        int idx = 0;
        for (int i = 0; i < N; i++) {
            s[i] = 'a' + (i % A);
        }
        s[N] = '\0';
        int L = 1;
        for (int i = 0; i < N - 1; i++) {
            if (s[i] == s[i + 1]) {
                L = 2;
                break;
            }
        }
        printf("%d %s\n", L, s);
    }
    return 0;
}

