code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int A = sc.nextInt();
            StringBuilder s = new StringBuilder();
            for (int i = 0; i < N; i++) {
                s.append((char)('a' + (i % A)));
            }
            int L = 1;
            for (int i = 0; i < N - 1; i++) {
                if (s.charAt(i) == s.charAt(i + 1)) {
                    L = 2;
                    break;
                }
            }
            System.out.println(L + " " + s.toString());
        }
    }
}

