const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, A] = readline().split(' ').map(Number);
    let s = '';
    for (let j = 0; j < N; j++) {
        s += String.fromCharCode('a'.charCodeAt(0) + (j % A));
    }
    let L = 1;
    for (let j = 0; j < N - 1; j++) {
        if (s[j] === s[j + 1]) {
            L = 2;
            break;
        }
    }
    console.log(L + ' ' + s);
}

